CREATE TYPE "TrainingSessionStatus" AS ENUM ('OPEN','FULL','COMING_SOON','HIDDEN');
CREATE TABLE "Training" ("id" TEXT NOT NULL,"slug" TEXT NOT NULL,"name" TEXT NOT NULL,"title" TEXT NOT NULL,"category" TEXT NOT NULL,"description" TEXT NOT NULL DEFAULT '',"pageUrl" TEXT NOT NULL,"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Training_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "Training_slug_key" ON "Training"("slug");
CREATE TABLE "TrainingSession" ("id" TEXT NOT NULL,"trainingId" TEXT NOT NULL,"title" TEXT NOT NULL,"startDate" TIMESTAMP(3) NOT NULL,"endDate" TIMESTAMP(3) NOT NULL,"examDate" TIMESTAMP(3),"priceCents" INTEGER NOT NULL,"priceLabel" TEXT NOT NULL,"location" TEXT NOT NULL,"status" "TrainingSessionStatus" NOT NULL DEFAULT 'OPEN',"seatsTotal" INTEGER,"seatsLeft" INTEGER,"registrationUrl" TEXT NOT NULL,"fundingNotes" TEXT NOT NULL DEFAULT '',"publicNotes" TEXT NOT NULL DEFAULT '',"internalNotes" TEXT NOT NULL DEFAULT '',"sortOrder" INTEGER NOT NULL DEFAULT 0,"isHighlighted" BOOLEAN NOT NULL DEFAULT false,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "TrainingSession_pkey" PRIMARY KEY ("id"));
ALTER TABLE "TrainingSession" ADD CONSTRAINT "TrainingSession_trainingId_fkey" FOREIGN KEY ("trainingId") REFERENCES "Training"("id") ON DELETE CASCADE ON UPDATE CASCADE;
CREATE TABLE "ChatLead" ("id" TEXT NOT NULL,"firstName" TEXT NOT NULL,"lastName" TEXT NOT NULL,"email" TEXT NOT NULL,"phone" TEXT NOT NULL,"trainingInterest" TEXT NOT NULL DEFAULT '',"message" TEXT NOT NULL DEFAULT '',"source" TEXT NOT NULL DEFAULT 'chat',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "ChatLead_pkey" PRIMARY KEY ("id"));
CREATE TABLE "ChatConversationLog" ("id" TEXT NOT NULL,"userMessage" TEXT NOT NULL,"assistantAnswer" TEXT NOT NULL,"selectedKnowledgeFiles" TEXT NOT NULL DEFAULT '',"selectedSessions" TEXT NOT NULL DEFAULT '',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "ChatConversationLog_pkey" PRIMARY KEY ("id"));
